import java.util.concurrent.atomic.AtomicInteger;
public class Main {
    public static void main(String[] args) {
        EventBus bus = new EventBus();
        AtomicInteger count = new AtomicInteger();
        bus.subscribe(new EventHandler() { public void handle(Event e) { count.incrementAndGet(); } public String getName() { return "H"; } }, UserEvent.class);
        bus.publish(new UserEvent("LOGIN", "alice"));
        bus.publish(new UserEvent("LOGIN", "bob"));
        System.out.println("OK_1 COUNT=" + count.get());
    }
}

