import java.util.concurrent.atomic.AtomicInteger;
public class Main {
    public static void main(String[] args) {
        EventBus bus = new EventBus();
        AtomicInteger count = new AtomicInteger();
        bus.subscribe(new EventHandler() { public void handle(Event e) { count.incrementAndGet(); } public String getName() { return "VIP"; } }, UserEvent.class, 10, ev -> ((UserEvent)ev).getUsername().equals("admin"));
        bus.publish(new UserEvent("A", "regular"));
        bus.publish(new UserEvent("A", "admin"));
        System.out.println("OK_2 COUNT=" + count.get());
    }
}

